import threading, time
from assay_engine.reasoning import seam

# Simulate 12 concurrent NORMAL calls each taking 0.5s (within timeout, not hung).
# With only 8 pool workers, calls 9-12 hit saturation guard while slots legitimately busy.
results = {"ok":0, "permanent":0, "other":0}
lock = threading.Lock()

def normal_call(d):
    def work():
        time.sleep(d)
        return "done"
    try:
        seam._with_timeout(work, 5.0, "normal")
        with lock: results["ok"]+=1
    except seam.PermanentReasoningError:
        with lock: results["permanent"]+=1
    except Exception:
        with lock: results["other"]+=1

threads=[threading.Thread(target=normal_call, args=(0.5,)) for _ in range(12)]
for t in threads: t.start()
for t in threads: t.join()
print("12 concurrent legit 0.5s calls, 8 workers:", results)
print("final inflight:", seam._inflight)
